query URE_FetchRecommendations($placement: String!, $site: String!, $skuId: String!, $relatedProductsCount: Int!, $additionalMinRelatedProductsCount: Int!, $groupIds: String!, $limit: Int!, $storeId: String!, $planPaidMembershipEffectiveType: String, $salesChannel: String!, $partyToken: String, $userToken: String, $visitorToken: String, $usePriceWithCart: Boolean!, $cartTimestamp: String!) {
